// Log resolution
// ---------------------------------------------------------------------------

function resolveWorkspace(input) {
  return (
    process.env.SESSION_KEEPER_WORKSPACE ||
    input.workspaceFolder ||
    input.cwd ||
    process.env.VSCODE_CWD ||
