node ./.github/skills/session-keeper/scripts/keep-session.mjs

# Capture a specific session log explicitly:
VSCODE_TARGET_SESSION_LOG="/path/to/debug-logs/<sessionId>" \
  node ./.github/skills/session-keeper/scripts/keep-session.mjs
```

Then re-run captured commands after review:

```bash
