    bases = variants.map((v) =>
      path.join(home, 'Library', 'Application Support', v, 'User', 'workspaceStorage'),
    );
  } else {
    bases = variants.map((v) => path.join(home, '.config', v, 'User', 'workspaceStorage'));
  }
  return bases;
}

