    const session = parseSession(logFile);
    const { commands, thoughts, files } = session;

    // 2a. Always write a session summary (the high-level overview).
    writeSummaryMarkdown(
      path.join(summaryDir, `${sessionId}.md`),
      sessionId,
      session,
